test_templates.foundry_access_bypass:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "${CONTRACT_PATH}";

contract AccessControlTest is Test {
    ${CONTRACT_NAME} public target;
    address public owner;
    address public attacker;

    function setUp() public {
        owner = makeAddr("owner");
        attacker = makeAddr("attacker");

        vm.prank(owner);
        target = new ${CONTRACT_NAME}();
    }

    function testAccessBypass() public {
        // Try to call privileged function as attacker
        vm.prank(attacker);

        // This should revert if access control is working
        // If it doesn't revert, access control is missing
        try target.${FUNCTION_NAME}() {
            // If we get here, access control is missing
            assertTrue(true, "Access control bypass successful - VULNERABLE");
        } catch {
            // Access control working as expected
            assertTrue(true, "Access control prevented unauthorized access");
        }
    }

    function testOnlyOwnerCanCall() public {
        // Owner should be able to call
        vm.prank(owner);
        target.${FUNCTION_NAME}();

        // Attacker should not be able to call
        vm.prank(attacker);
        vm.expectRevert();
        target.${FUNCTION_NAME}();
    }
}
